    long long count = 0;
    int n = points.size();
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            // Calculate the slope between points[i] and points[j]
            long long dx1 = points[i][0] - points[j][0];
            long long dy1 = points[i][1] - points[j][1];
            // Use a normalized form to avoid precision issues
            long long gcd1 = std::gcd(dx1, dy1);
            dx1 /= gcd1;
            dy1 /= gcd1;
            // Store the slope as a pair
            std::pair<long long, long long> slope1 = {dx1, dy1};

            // Map to count pairs of points with the same slope
            std::unordered_map<std::pair<long long, long long>, int> slopeMap;
            for (int k = 0; k < n; ++k) {
                if (k == i || k == j) continue;
                long long dx2 = points[i][0] - points[k][0];
                long long dy2 = points[i][1] - points[k][1];
                long long gcd2 = std::gcd(dx2, dy2);
                dx2 /= gcd2;
                dy2 /= gcd2;
                std::pair<long long, long long> slope2 = {dx2, dy2};
                slopeMap[slope2]++;
            }

            // For each slope, count the number of pairs that have the same slope
            for (auto& [slope, cnt] : slopeMap) {
                // If there are at least two points with this slope, they can form a pair
                if (cnt >= 2) {
                    count += (long long)cnt * (long long)(cnt - 1) / 2;
                }
            }
        }
    }

    // Each trapezoid is counted twice (once for each pair of parallel sides)
    return count / 2;
}

